/* Node.js pseudo: append event and replay stream */
const { v4: uuid } = require('uuid')

async function placeOrder(eventStore, order) {
  const event = { id: uuid(), type: 'OrderPlaced', data: order, ts: Date.now(), version: 1 }
  await eventStore.append(`order-${order.id}`, event)
  return event
}

async function rebuildOrderState(eventStore, orderId) {
  const events = await eventStore.loadStream(`order-${orderId}`)
  return events.reduce((state, e) => {
    switch (e.type) {
      case 'OrderPlaced': return { ...state, status: 'Pending', items: e.data.items }
      case 'PaymentSucceeded': return { ...state, status: 'Paid' }
      case 'ItemShipped': return { ...state, status: 'Shipped' }
      default: return state
    }
  }, { id: orderId })
}
